function getCacheControl(pathname) {
  if (pathname === '/' || pathname.endsWith('.html')) {
    return 'no-cache';
  }

  return 'public, max-age=31536000, immutable';
}

function serveAsset(pathname, asset) {
  const headers = new Headers({
    'Content-Type': asset.contentType,
    'Cache-Control': getCacheControl(pathname),
  });

  if (asset.isBase64) {
    const binaryString = atob(asset.content);
    const bytes = Uint8Array.from(binaryString, (character) => character.charCodeAt(0));
    return new Response(bytes, { headers });
  }

  return new Response(asset.content, { headers });
}

export default {
  async fetch(request) {
    const url = new URL(request.url);
    const pathname = url.pathname || '/';
    const directAsset = assets[pathname];

    if (directAsset) {
      return serveAsset(pathname, directAsset);
    }

    const spaEntry = assets['/index.html'];

    if (spaEntry) {
      return serveAsset('/index.html', spaEntry);
    }

    return new Response('Missing /index.html asset', { status: 500 });
  },
};
